package clusterspec

import (
	"strings"
	"testing"
)

// allOn is the default component set (every component enabled except DefaultDisabled).
func allOn() map[string]ComponentToggle {
	m := map[string]ComponentToggle{}
	for _, c := range Components {
		m[c.Name] = ComponentToggle{Enabled: !c.DefaultDisabled}
	}
	return m
}

func TestRenderManifestKustomization(t *testing.T) {
	out := RenderManifestKustomization(allOn())
	// Generated header + a couple of enabled components' resources + the
	// volume-labeler patch.
	for _, want := range []string{
		"GENERATED by", "kind: Kustomization",
		"- argocd",
		"- external-secrets/cluster-secret-store-openbao.yaml",
		"- harbor/harbor-registry-s3-externalsecret.yaml",
		"patches:", "path: linode-volume-labeler-region-patch.yaml", "kind: CronJob",
	} {
		if !strings.Contains(out, want) {
			t.Errorf("manifest kustomization missing %q:\n%s", want, out)
		}
	}

	// Disabling harbor drops its resource (and only its resource).
	off := allOn()
	off["harbor"] = ComponentToggle{Enabled: false}
	if strings.Contains(RenderManifestKustomization(off), "harbor/harbor-registry-s3-externalsecret.yaml") {
		t.Error("disabled harbor should drop its manifest resource")
	}
}

func TestRenderArgoKustomization(t *testing.T) {
	out := RenderArgoKustomization(allOn())
	for _, want := range []string{"platform-support-project.yaml", "applications/openbao.yaml", "applications/cluster-foundation.yaml"} {
		if !strings.Contains(out, want) {
			t.Errorf("argocd kustomization missing %q:\n%s", want, out)
		}
	}
	// Deterministic registry order: cluster-foundation (registry pos 2) before openbao.
	if i, j := strings.Index(out, "cluster-foundation.yaml"), strings.Index(out, "openbao.yaml"); i < 0 || j < 0 || i > j {
		t.Errorf("argocd apps not in registry order:\n%s", out)
	}
}

func TestComponentRegistry_AplCoreMapping(t *testing.T) {
	// The unified model routes some components to the apl-core (values.yaml) backend.
	obs, ok := LookupComponent("observability")
	if !ok {
		t.Fatal("observability component missing")
	}
	for _, app := range []string{"prometheus", "loki", "grafana"} {
		found := false
		for _, a := range obs.AplCoreApps {
			if a == app {
				found = true
			}
		}
		if !found {
			t.Errorf("observability should map to apl-core app %q (got %v)", app, obs.AplCoreApps)
		}
	}
	// harbor spans BOTH backends.
	h, _ := LookupComponent("harbor")
	if len(h.AplCoreApps) == 0 || len(h.ManifestResources) == 0 {
		t.Errorf("harbor should use both backends; got aplCore=%v manifest=%v", h.AplCoreApps, h.ManifestResources)
	}
	// ComponentEnabled honors DefaultDisabled (dns) and a partial map.
	if ComponentEnabled(map[string]ComponentToggle{}, "dns") {
		t.Error("dns is DefaultDisabled → not enabled by default")
	}
	if !ComponentEnabled(map[string]ComponentToggle{}, "openbao") {
		t.Error("openbao defaults enabled")
	}
}
